import React, { useState, useEffect } from 'react';
import { Typography, Button, Paper } from '@mui/material';
import { Link, useParams } from 'react-router-dom';
import fetchModel from '../../lib/fetchModelData';
import './styles.css';

function UserDetail({ setContext }) {
  const { userId } = useParams();
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetchModel(`/user/${userId}`)
      .then((response) => {
        setUser(response.data);
        setContext(`${response.data.first_name} ${response.data.last_name}`);
      })
      .catch((err) => {
        console.error("Lỗi lấy chi tiết người dùng:", err);
      });
  }, [userId, setContext]);

  if (!user) {
    return <Typography variant="body1">Đang tải thông tin người dùng...</Typography>;
  }

  return (
    <Paper elevation={3} style={{ padding: '20px' }}>
      <Typography variant="h4" gutterBottom>
        {user.first_name} {user.last_name}
      </Typography>

      <Typography variant="h6" color="textSecondary">Thông tin cá nhân:</Typography>
      <Typography variant="body1"><strong>Vị trí:</strong> {user.location}</Typography>
      <Typography variant="body1"><strong>Nghề nghiệp:</strong> {user.occupation}</Typography>
      <Typography variant="body1" style={{ marginTop: '10px' }}>
        <strong>Mô tả:</strong> {user.description}
      </Typography>

      <Button
        variant="contained"
        color="primary"
        component={Link}
        to={`/photos/${user._id}`}
        style={{ marginTop: '20px' }}
      >
        Xem ảnh của {user.first_name}
      </Button>
    </Paper>
  );
}

export default UserDetail;
